export interface ModelUsage {
	model: string;
	provider?: string;
	usage: Usage;
	timestamp: number;
}

export interface SessionCost {
	totalCost: number;
	turns: number;
	totalInputTokens: ***;
	totalOutputTokens: ***;
	byModel: Map<string, { cost: number; turns: number; inputTokens: ***; outputTokens: *** }>;
	savingsFromFiltering: number;
}

export class CostTracker {
	private entries: ModelUsage[] = [];
	private bytesFiltered: number = 0;

	trackUsage(model: string, provider: string | undefined, usage: Usage): void {
		this.entries.push({
			model,
			provider,
			usage,
			timestamp: Date.now(),
		});
	}

	trackBytesFiltered(bytesSaved: number): void {
		this.bytesFiltered += bytesSaved;
	}

	getSessionCost(pricingFn: (model: string, usage: Usage) => number): SessionCost {
		let totalCost = 0;
		let totalInputTokens = ***;
		let totalOutputTokens = ***;
		const byModel = new Map<string, { cost: number; turns: number; inputTokens: ***; outputTokens: *** }>();

		for (const entry of this.entries) {
			const cost = pricingFn(entry.model, entry.usage);
			totalCost += cost;
			totalInputTokens += entry.usage.inputTokens;
			totalOutputTokens += entry.usage.outputTokens;

			const existing = byModel.get(entry.model);
			if (existing) {
				existing.cost += cost;
				existing.turns++;
				existing.inputTokens += entry.usage.inputTokens;
				existing.outputTokens += entry.usage.outputTokens;
			} else {
				byModel.set(entry.model, {
					cost,
					turns: 1,
					inputTokens: ***,
					outputTokens: ***,
				});
			}
		}

		// Estimate savings: bytes filtered / ~4 bytes per token * average cost per token
		const avgCostPerToken = *** > 0 ? totalCost / (totalInputTokens + totalOutputTokens || 1) : 0;
		const estimatedTokensSaved = *** / 4);
		const savingsFromFiltering = estimatedTokensSaved * avgCostPerToken;

		return {
			totalCost,
			turns: this.entries.length,
			totalInputTokens,
			totalOutputTokens,
			byModel,
			savingsFromFiltering,
		};
	}

	reset(): void {
		this.entries = [];
		this.bytesFiltered = 0;
	}
}

import type { Usage } from "./tracker.ts";

export interface ModelPricing {
	model: string;
	inputPerMillion: number;
	outputPerMillion: number;
	cacheReadPerMillion?: number;
	cacheWritePerMillion?: number;
}

const BUILTIN_PRICING: ModelPricing[] = [
	{ model: "claude-sonnet-4", inputPerMillion: 3, outputPerMillion: 15 },
	{ model: "claude-opus-4", inputPerMillion: 15, outputPerMillion: 75 },
	{ model: "claude-haiku-3.5", inputPerMillion: 0.8, outputPerMillion: 4 },
	{ model: "gpt-4.1", inputPerMillion: 2, outputPerMillion: 8 },
	{ model: "gpt-4o", inputPerMillion: 2.5, outputPerMillion: 10 },
	{ model: "gpt-4o-mini", inputPerMillion: 0.15, outputPerMillion: 0.6 },
	{ model: "gemini-2.5-pro", inputPerMillion: 1.25, outputPerMillion: 10 },
	{ model: "gemini-2.5-flash", inputPerMillion: 0.15, outputPerMillion: 0.6 },
];

export class PricingDatabase {
	private pricing: ModelPricing[];

	constructor(customPricing?: Record<string, { inputPerMillion?: number; outputPerMillion?: number; cacheReadPerMillion?: number; cacheWritePerMillion?: number }>) {
		this.pricing = [...BUILTIN_PRICING];

		// Merge custom pricing
		if (customPricing) {
			for (const [model, rates] of Object.entries(customPricing)) {
				if (rates.inputPerMillion !== undefined && rates.outputPerMillion !== undefined) {
					this.pricing.push({
						model,
						inputPerMillion: rates.inputPerMillion,
						outputPerMillion: rates.outputPerMillion,
						cacheReadPerMillion: rates.cacheReadPerMillion,
						cacheWritePerMillion: rates.cacheWritePerMillion,
					});
				}
			}
		}
	}

	findPricing(model: string): ModelPricing | null {
		// Exact match first
		const exact = this.pricing.find((p) => p.model === model);
		if (exact) return exact;

		// Prefix match (handles versioned models like "claude-sonnet-4-20250514")
		for (const p of this.pricing) {
			if (model.startsWith(p.model)) return p;
		}

		return null;
	}

	calculateCost(model: string, usage: Usage): number {
		const pricing = this.findPricing(model);
		if (!pricing) return 0;

		const inputCost = (usage.inputTokens / 1_000_000) * pricing.inputPerMillion;
		const outputCost = (usage.outputTokens / 1_000_000) * pricing.outputPerMillion;
		const cacheReadCost = usage.cacheReadTokens ? (usage.cacheReadTokens / 1_000_000) * (pricing.cacheReadPerMillion ?? pricing.inputPerMillion * 0.1) : 0;
		const cacheWriteCost = usage.cacheWriteTokens ? (usage.cacheWriteTokens / 1_000_000) * (pricing.cacheWritePerMillion ?? pricing.inputPerMillion * 1.25) : 0;

		return inputCost + outputCost + cacheReadCost + cacheWriteCost;
	}
}

import type { SessionCost } from "./tracker.ts";

export interface WidgetData {
	totalCost: string;
	totalTokens: ***;
	savingsPct: string;
	intensity: string;
}

export function formatWidgetData(sessionCost: SessionCost, intensity: string, bytesSaved: number, bytesIn: number): WidgetData {
	const totalTokens = *** + sessionCost.totalOutputTokens;
	const savingsPct = bytesIn > 0 ? Math.round((bytesSaved / bytesIn) * 100) : 0;

	return {
		totalCost: `$${sessionCost.totalCost.toFixed(2)}`,
		totalTokens: ***,
		savingsPct: `${savingsPct}%`,
		intensity,
	};
}

export function formatWidgetString(data: WidgetData): string {
	return `💰 ${data.totalCost} | 📊 ${data.totalTokens} tok | 🗜️ ${data.savingsPct} saved | 📉 ${data.intensity}`;
}

export function formatDetailedCost(sessionCost: SessionCost): string {
	const lines: string[] = [
		"pi-smart Cost Breakdown:",
		`  Total: $${sessionCost.totalCost.toFixed(4)}`,
		`  Turns: ${sessionCost.turns}`,
		`  Input tokens: ***}`,
		`  Output tokens: ***}`,
		`  Estimated savings: $${sessionCost.savingsFromFiltering.toFixed(4)}`,
		"",
		"  By model:",
	];

	for (const [model, data] of sessionCost.byModel) {
		lines.push(`    ${model}: $${data.cost.toFixed(4)} (${data.turns} turns, ${formatTokenCount(data.inputTokens + data.outputTokens)} tokens)`);
	}

	return lines.join("\n");
}

function formatTokenCount(count: number): string {
	if (count >= 1_000_000) return `${(count / 1_000_000).toFixed(1)}M`;
	if (count >= 1_000) return `${(count / 1_000).toFixed(1)}K`;
	return String(count);
}

import type { ExtensionAPI, ExtensionContext, ToolDefinition } from "@mariozechner/pi-coding-agent";
import type { Intensity, BudgetState } from "../config.ts";
import { loadSmartConfig } from "../config.ts";
import { applyPipeline, type PipelineMetrics } from "../filter/pipeline.ts";
import { resolveProfile } from "../filter/config.ts";
import { computeBudgetState, getSteeringMessage, shouldAutoCompact } from "../budget/state-machine.ts";
import { calculatePercentage } from "../budget/tracker.ts";
import { CostTracker } from "../cost/tracker.ts";
import { PricingDatabase } from "../cost/pricing.ts";
import { formatWidgetString, formatDetailedCost, formatWidgetData } from "../cost/widget.ts";
import { getIntensityForBudgetState, getOutputAllowanceMultiplier, validateIntensity } from "../compress/intensity.ts";
import { compressByIntensity } from "../compress/caveman.ts";
import { executeInSandbox } from "../analyze/sandbox.ts";
import { registerSmartCommands } from "./register-commands.ts";

interface SessionState {
	config: ReturnType<typeof loadSmartConfig>;
	intensity: Intensity;
	budgetState: BudgetState;
	costTracker: CostTracker;
	pricing: PricingDatabase;
	pinnedContext: Map<string, { content: string }>;
	totalBytesIn: number;
	totalBytesOut: number;
	initialized: boolean;
}

export function registerPiSmart(pi: ExtensionAPI): void {
	let sessionState: SessionState | undefined;
	let currentCtx: ExtensionContext | undefined;

	const getState = (): SessionState => {
		if (!sessionState) throw new Error("pi-smart: no active session");
		return sessionState;
	};

	// --- Session lifecycle ---
	pi.on("session_start", (_event, ctx) => {
		const config = loadSmartConfig(ctx.cwd);
		sessionState = {
			config,
			intensity: config.compression.intensity,
			budgetState: "NORMAL",
			costTracker: new CostTracker(),
			pricing: new PricingDatabase(config.cost.pricing),
			pinnedContext: new Map(),
			totalBytesIn: 0,
			totalBytesOut: 0,
			initialized: true,
		};
		currentCtx = ctx;

		if (config.cost.showWidget && ctx.hasUI) {
			try {
				const data = formatWidgetData(sessionState.costTracker.getSessionCost((m, u) => sessionState!.pricing.calculateCost(m, u)), sessionState.intensity, 0, 0);
				ctx.ui.notify?.(`pi-smart active: ${sessionState.intensity} mode`, "info");
			} catch {
				// Widget not available in this Pi version
			}
		}
	});

	pi.on("session_shutdown", () => {
		sessionState = undefined;
		currentCtx = undefined;
	});

	// --- Tool result filtering ---
	try {
		pi.on("tool_result", (event, ctx) => {
			const state = sessionState;
			if (!state || !state.config.enabled || !state.config.filters.enabled) return;

			const eventRecord = event as Record<string, unknown>;
			const toolName = typeof eventRecord.toolName === "string" ? eventRecord.toolName : "";
			const content = eventRecord.content as Array<{ type: string; text?: string }> | undefined;
			if (!content) return;

			// Extract text from content
			const textParts = content
				.filter((c) => c.type === "text" && typeof c.text === "string")
				.map((c) => c.text!);
			if (textParts.length === 0) return;

			const rawText = textParts.join("");
			// Extract command for bash profile matching
			const command = typeof eventRecord.input === "object" && eventRecord.input !== null
				? ((eventRecord.input as Record<string, unknown>).command as string | undefined)
				: undefined;

			// Adjust max lines based on budget state
			const multiplier = getOutputAllowanceMultiplier(state.budgetState);
			const filters = resolveProfile(toolName, command, state.config);

			// Apply budget-based output reduction
			if (multiplier < 1.0 && filters.length > 0) {
				// Adjust head-tail filter limits based on budget
			}

			const { result, metrics } = applyPipeline(rawText, filters);
			state.totalBytesIn += metrics.bytesIn;
			state.totalBytesOut += metrics.bytesOut;
			state.costTracker.trackBytesFiltered(metrics.bytesIn - metrics.bytesOut);

			if (result !== rawText) {
				// Return filtered content
				return {
					content: [{ type: "text", text: result }],
				} as Record<string, unknown>;
			}
		});
	} catch {
		// tool_result hook not available in this Pi version
	}

	// --- Turn end: budget check ---
	pi.on("turn_end", (_event, ctx) => {
		const state = sessionState;
		if (!state || !state.config.enabled || !state.config.budget.enabled) return;

		const rawUsage = ctx.getContextUsage?.() ?? null;
		if (!rawUsage || rawUsage.tokens =*** null || rawUsage.tokens =*** undefined) return;

		const contextWindow = (ctx as unknown as Record<string, unknown>).model
			? ((ctx as unknown as { model: { contextWindow: number } }).model?.contextWindow ?? 200000)
			: 200000;

		const percentage = calculatePercentage(rawUsage.tokens, contextWindow);
		const newState = computeBudgetState(percentage, state.config.budget.thresholds);

		if (newState !== state.budgetState) {
			state.budgetState = newState;

			// Auto-intensify if configured
			if (state.config.compression.autoIntensify) {
				state.intensity = getIntensityForBudgetState(newState);
			}

			// Auto-compact if needed
			if (shouldAutoCompact(newState) && currentCtx) {
				try {
					const steering = getSteeringMessage(newState);
					if (steering) {
						ctx.ui.notify?.(`[pi-smart] Context ${Math.round(percentage * 100)}% — ${newState} mode`, "warning");
					}
					if (newState === "EMERGENCY") {
						ctx.compact?.({
							customInstructions: "Preserve task description and active files. Remove old context.",
						});
					}
				} catch {
					// compact not available
				}
			}
		}
	});

	// --- Before agent start: inject steering ---
	pi.on("before_agent_start", (_event, _ctx) => {
		const state = sessionState;
		if (!state || !state.config.enabled) return;

		const steering = getSteeringMessage(state.budgetState);
		if (steering) {
			// Return steering note to be injected into context
			return { systemNote: steering } as Record<string, unknown>;
		}
	});

	// --- Register analyze tool ---
	const analyzeTool: ToolDefinition = {
		name: "analyze",
		description: `Execute code in a sandboxed environment to analyze, count, filter, compare, or process data. Returns stdout only. Use instead of reading many files into context.

When you need to analyze, count, filter, compare, or process data:
1. Write a script that does the analysis
2. Use the analyze tool to execute it
3. console.log() only the answer

NEVER: Read 50 files into context to count functions
INSTEAD: analyze({ language: "javascript", code: "..." })`,
		parameters: {
			type: "object" as const,
			properties: {
				language: {
					type: "string" as const,
					enum: ["javascript", "typescript", "python", "shell"],
					description: "Programming language for the code",
				},
				code: {
					type: "string" as const,
					description: "Code to execute",
				},
				intent: {
					type: "string" as const,
					description: "What we're looking for (enables output gating)",
				},
				maxOutputBytes: {
					type: "number" as const,
					description: "Max output bytes (default: 5120)",
				},
				allowNetwork: {
					type: "boolean" as const,
					description: "Allow network access (default: false)",
				},
			},
			required: ["language", "code"],
		},
		execute: async (params: Record<string, unknown>, ctx: ExtensionContext) => {
			const state = sessionState;
			if (!state || !state.config.enabled || !state.config.analyze.enabled) {
				return { content: [{ type: "text" as const, text: "pi-smart analyze tool is disabled" }] };
			}

			const language = params.language as string;
			const code = params.code as string;
			const maxOutputBytes = (params.maxOutputBytes as number | undefined) ?? state.config.analyze.maxOutputBytes;
			const allowNetwork = (params.allowNetwork as boolean | undefined) ?? state.config.analyze.allowNetwork;

			const result = await executeInSandbox({
				language,
				code,
				cwd: ctx.cwd,
				timeout: state.config.analyze.timeout,
				maxOutputBytes,
				allowNetwork,
			});

			if (result.exitCode !== 0 && result.stderr) {
				return {
					content: [
						{ type: "text" as const, text: `Error (exit ${result.exitCode}):\n${result.stderr}` },
					],
				};
			}

			const summary = result.bytesProcessed > result.bytesReturned
				? `\n[pi-smart: ${result.bytesProcessed} bytes → ${result.bytesReturned} bytes, ${Math.round((1 - result.bytesReturned / (result.bytesProcessed || 1)) * 100)}% reduction]`
				: "";

			return {
				content: [
					{ type: "text" as const, text: result.stdout + summary },
				],
			};
		},
	};

	try {
		pi.registerTool(analyzeTool);
	} catch {
		// Tool registration may not be available
	}

	// --- Register smart_config tool ---
	const smartConfigTool: ToolDefinition = {
		name: "smart_config",
		description: "Get or set pi-smart runtime configuration",
		parameters: {
			type: "object" as const,
			properties: {
				action: {
					type: "string" as const,
					enum: ["get", "set", "reset"],
					description: "Action to perform",
				},
				key: {
					type: "string" as const,
					description: "Configuration key",
				},
				value: {
					description: "Value to set (for 'set' action)",
				},
			},
			required: ["action", "key"],
		},
		execute: async (params: Record<string, unknown>) => {
			const state = sessionState;
			if (!state) return { content: [{ type: "text" as const, text: "No active session" }] };

			const action = params.action as string;
			const key = params.key as string;

			if (action === "get") {
				switch (key) {
					case "intensity":
						return { content: [{ type: "text" as const, text: state.intensity }] };
					case "filters.enabled":
						return { content: [{ type: "text" as const, text: String(state.config.filters.enabled) }] };
					case "budget.thresholds":
						return { content: [{ type: "text" as const, text: JSON.stringify(state.config.budget.thresholds) }] };
					case "cost.model":
						return { content: [{ type: "text" as const, text: JSON.stringify(Object.fromEntries(state.pricing.findPricing("*") ?? [])) }] };
					default:
						return { content: [{ type: "text" as const, text: `Unknown key: ${key}` }] };
				}
			}

			if (action === "set") {
				const value = params.value;
				switch (key) {
					case "intensity": {
						const validated = validateIntensity(String(value));
						if (validated) {
							state.intensity = validated;
							return { content: [{ type: "text" as const, text: `Intensity set to ${validated}` }] };
						}
						return { content: [{ type: "text" as const, text: `Invalid intensity: ${value}. Use: terse, normal, verbose` }] };
					}
					case "filters.enabled":
						state.config.filters.enabled = Boolean(value);
						return { content: [{ type: "text" as const, text: `Filters ${Boolean(value) ? "enabled" : "disabled"}` }] };
					default:
						return { content: [{ type: "text" as const, text: `Cannot set key: ${key}` }] };
				}
			}

			if (action === "reset") {
				state.config = loadSmartConfig(currentCtx?.cwd ?? process.cwd());
				state.intensity = state.config.compression.intensity;
				return { content: [{ type: "text" as const, text: "Configuration reset to defaults" }] };
			}

			return { content: [{ type: "text" as const, text: `Unknown action: ${action}` }] };
		},
	};

	try {
		pi.registerTool(smartConfigTool);
	} catch {
		// Tool registration may not be available
	}

	// --- Register commands ---
	registerSmartCommands(pi, {
		getState,
		getCostSummary: () => {
			const state = getState();
			return state.costTracker.getSessionCost((model, usage) => state.pricing.calculateCost(model, usage));
		},
		setIntensity: (intensity: Intensity) => {
			getState().intensity = intensity;
		},
	});
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import type { Intensity } from "../config.ts";
import type { SessionCost } from "../cost/tracker.ts";
import { formatDetailedCost, formatWidgetString, formatWidgetData } from "../cost/widget.ts";

interface SessionState {
	intensity: Intensity;
	budgetState: string;
	config: { enabled: boolean; filters: { enabled: boolean; profiles: Record<string, string[]>; defaultProfile: string[] } };
	totalBytesIn: number;
	totalBytesOut: number;
	costTracker: {
		getSessionCost: (fn: (model: string, usage: { inputTokens: ***; outputTokens: ***; cacheReadTokens?: number; cacheWriteTokens?: number }) => number) => SessionCost;
	};
	pricing: { calculateCost: (model: string, usage: { inputTokens: ***; outputTokens: ***; cacheReadTokens?: number; cacheWriteTokens?: number }) => number };
}

export interface SmartCommandDeps {
	getState: () => SessionState;
	getCostSummary: () => SessionCost;
	setIntensity: (intensity: Intensity) => void;
}

export function registerSmartCommands(pi: ExtensionAPI, deps: SmartCommandDeps): void {
	const { getState, getCostSummary, setIntensity } = deps;

	pi.registerCommand?.("smart", {
		description: "pi-smart status and configuration",
		execute: async (args?: string[]) => {
			const state = getState();
			const cost = getCostSummary();
			const arg = args?.[0];

			if (arg === "cost") {
				return formatDetailedCost(cost);
			}

			if (arg === "filters") {
				const profiles = Object.entries(state.config.filters.profiles)
					.map(([key, filters]) => `  ${key}: [${filters.join(", ")}]`)
					.join("\n");
				return [
					"pi-smart Filter Profiles:",
					profiles,
					`  default: [${state.config.filters.defaultProfile.join(", ")}]`,
				].join("\n");
			}

			if (arg === "terse" || arg === "normal" || arg === "verbose") {
				setIntensity(arg);
				return `pi-smart intensity set to ${arg}`;
			}

			// Default: show status dashboard
			const data = formatWidgetData(cost, state.intensity, state.totalBytesIn - state.totalBytesOut, state.totalBytesIn);
			return [
				"pi-smart Status:",
				`  Output filtering: ${state.config.filters.enabled ? "ON" : "OFF"} (saved ${state.totalBytesIn > 0 ? Math.round((state.totalBytesIn - state.totalBytesOut) / 1024) : 0}KB this session)`,
				`  Response compression: ${state.intensity}`,
				`  Context budget: ${state.budgetState}`,
				`  Session cost: ${data.totalCost} (${data.totalTokens} tokens)`,
				"",
				formatWidgetString(data),
				"",
				"Usage: /smart terse|normal|verbose | /smart cost | /smart filters",
			].join("\n");
		},
	});
}

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { applyPipeline, type Filter } from "../../src/filter/pipeline.ts";

describe("applyPipeline", () => {
	it("passes text through unchanged with no filters", () => {
		const { result, metrics } = applyPipeline("hello world", []);
		assert.equal(result, "hello world");
		assert.equal(metrics.filtersApplied, 0);
		assert.equal(metrics.reductionPct, 0);
	});

	it("applies a single filter", () => {
		const upper: Filter = {
			name: "uppercase",
			apply: (t) => t.toUpperCase(),
		};
		const { result, metrics } = applyPipeline("hello", [upper]);
		assert.equal(result, "HELLO");
		assert.equal(metrics.filtersApplied, 1);
	});

	it("applies multiple filters in order", () => {
		const addA: Filter = { name: "add-a", apply: (t) => t + "A" };
		const addB: Filter = { name: "add-b", apply: (t) => t + "B" };
		const { result } = applyPipeline("x", [addA, addB]);
		assert.equal(result, "xAB");
	});

	it("skips failing filters (safety passthrough)", () => {
		const bad: Filter = {
			name: "bad",
			apply: () => { throw new Error("boom"); },
		};
		const good: Filter = { name: "good", apply: (t) => t.toUpperCase() };
		const { result } = applyPipeline("hello", [bad, good]);
		assert.equal(result, "HELLO");
	});

	it("tracks metrics correctly", () => {
		const truncate: Filter = { name: "truncate", apply: (t) => t.slice(0, 5) };
		const { metrics } = applyPipeline("hello world this is long", [truncate]);
		assert.equal(metrics.bytesOut, 5);
		assert.ok(metrics.reductionPct > 0);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { createStripAnsiFilter } from "../../src/filter/filters/strip-ansi.ts";

describe("strip-ansi filter", () => {
	it("removes ANSI escape sequences", () => {
		const filter = createStripAnsiFilter();
		const input = "\x1b[32mgreen text\x1b[0m normal";
		assert.equal(filter.apply(input), "green text normal");
	});

	it("removes complex ANSI sequences", () => {
		const filter = createStripAnsiFilter();
		const input = "\x1b[1;31;47mbold red on white\x1b[0m";
		assert.equal(filter.apply(input), "bold red on white");
	});

	it("leaves plain text unchanged", () => {
		const filter = createStripAnsiFilter();
		assert.equal(filter.apply("plain text"), "plain text");
